var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제3 방위선, 거점 기지","JPN":"人類統合防衛軍第3防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 3rd Defense Line","TWN":"人類共同保衛軍第三防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"호오, 내게 무슨 볼일이지, 소령.","JPN":"ほお、私に何の用だ、少佐。","ENG":"Ho-oh, you wanted to see me, Major?","TWN":"喔？你有什麼事嗎，少校？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네들도 내 이주 플랜에 관심이라도 생긴 건가?","JPN":"君たちも私の移住計画に興味が湧いたのか？","ENG":"Finally taking an interest in my emigration plan?","TWN":"你們也對我的移居計畫感興趣了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어떤가? 지금이라도 우리에게 등대를 넘기면, 아이기스에 자네들의 자리를 마련해주지.","JPN":"どうだ？　今からでもこちらに灯台を引き渡せば、アイギスに君たちの席を用意しよう。","ENG":"What do you say? If you hand over the Lighthouse, I will make room for you all in Aegis.","TWN":"如何？現在把燈塔交給我們，埃癸斯就有你們的一席之地。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 글쎄요?","JPN":"ハハ、どうでしょう？","ENG":"Hah hah, I dunno.","TWN":"哈哈，是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 일류 용병이긴 하지만, 저희 부모님은 무척 평범하신 분들이거든요.","JPN":"私は一流の傭兵ですが、親は二人ともとても平凡でしてね。","ENG":"Although I might be a first-class mercenary, my parents are just normal people.","TWN":"雖然我是一流傭兵，但我父母都是非常平凡的人呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시 저희 부모님 자리도 마련해주신다면 뭐, 조금 고민해볼까요?","JPN":"もし両親の席も用意してくれるなら、まぁ、少しは考えてもいいんですが？","ENG":"If you also make room for them, I'll consider it?","TWN":"要是給我的父母也安排了位置的話，我就稍微考慮看看？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 유감이지만 그건 어렵겠는데?","JPN":"ふふ、残念ながらそれは難しそうだ。","ENG":"Ha ha, that will be difficult, I'm afraid.","TWN":"呵呵，真是遺憾，這恐怕很困難。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그럼 자네는 어떤가, 론?","JPN":"君はどうする、ローン？","ENG":"Then what about you, Lone?","TWN":"那麼你呢，隆利？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"안토노프 양, 대체 왜 이렇게까지……","JPN":"アントノフさん、なぜここまで……","ENG":"Antonov, why are you doing this...?","TWN":"安東諾夫，你到底為什麼……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프 행정관.","JPN":"アントノフ行政官。","ENG":"Officer Antonov.","TWN":"安東諾夫行政官。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"미안하지만, 저는 딱히 당신과 대화를 나누러 온 것이 아닙니다.","JPN":"申し訳ありませんが、私は別にあなたと話をするために来たわけではありません。","ENG":"I'm sorry, but I didn't come here to chit-chat with you.","TWN":"很抱歉，我不是來和你閒聊的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"스스로를 엑자일러라고 주장하는 <color=#ffd34c>정신 이상자</color> 를 체포하러 온 것뿐이죠.","JPN":"自らをエグザイラーと称する、<color=#ffd34c>精神異常者</color>を逮捕しに来たんです。","ENG":"I'm here to arrest a <color=#ffd34c>lunatic</color> who claims to be an Exile.","TWN":"我來這裡是為了逮捕自稱是流浪者的<color=#ffd34c>精神病患</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"내가 정신 이상자라고? 후후, 재밌군.","JPN":"私が精神異常者だと？　ふふ、面白い。","ENG":"Me? A lunatic? Ha ha, interesting.","TWN":"精神病患？是在說我嗎？呵呵，真是有趣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 군 기강을 분열시키고 있어요. 지금부터 그 책임을 묻겠습니다.","JPN":"あなたは軍の結束を揺るがしています。今からその責任を問います。","ENG":"You are disrupting the morale of the army. And I demand that you take responsibility for it.","TWN":"你企圖分裂軍隊紀律，即刻起我們將追究你的責任。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"분열이라고?","JPN":"揺るがしている？","ENG":"Disrupting the morale?","TWN":"分裂嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"틀렸어. 나는 자네가 했던 것처럼 그들에게도 선택지를 주었을 뿐이야.","JPN":"違うな。私は君がそうしたように、彼らに選択肢を与えたまでだ。","ENG":"You are wrong. Just like you, I gave them a choice.","TWN":"你錯了。我只是像你做過的那樣，給了他們選擇而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그들이 이 세계에 남아서 싸우든 이주 플랜에 동참하든 선택은 그들의 몫일 텐데?","JPN":"この世界に残って戦うか、移住計画に乗るか、選択は彼ら次第のはずだが？","ENG":"It is their will to choose whether to fight for this world or join me.","TWN":"那些人是要留在這個世界戰鬥，還是參與移居計畫，都是他們自己的選擇吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"틀렸습니다. 지금은 국가 비상 사태입니다. 그리고 당신은 개인 목적을 위해 병력을 모았어.","JPN":"違います。今は国家非常事態なんです。そしてあなたは個人的な目的のために兵力を集めた。","ENG":"Therein lies your error. We are in a state of national emergency. And you are recruiting individuals for your own ends.","TWN":"這就是問題所在，眼下正處於緊急情況，而你卻在為了個人目地在招募兵力。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이건 인류 통합 방위군 정부에 대한 명백한 반역 행위입니다.","JPN":"これは人類統合防衛軍政府に対する、明らかな敵対行為です。","ENG":"Clearly, this constitutes treason against the United Humankind Government.","TWN":"這對於人類共同保衛軍來說，屬於決不允許的背叛行為。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이에 따라, 당신이 불법 점유하고 있던 로스트 쉽, 그 밖에 테크 장비들은 현시간부로 압류.","JPN":"これにより、あなたが不法に占有していたロストシップ、その他のテクノロジー装備は現時刻をもって押収。","ENG":"Accordingly, we will seize your illegally occupied Lost Ship and all of its tech gear immediately.","TWN":"因此，我們將即刻起扣押你非法佔有的失落艦船，以及技術裝備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전부 방위군 정부의 소유물로 귀속됩니다.","JPN":"すべて防衛軍政府の所有となります。","ENG":"The ownership of it will be transferred over to the United Humankind Government.","TWN":"並將其所有權全部移交至保衛軍所有。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어차피 자네들은 사용하지도 못할 텐데?","JPN":"どうせ君たちには使うこともできないと思うが。","ENG":"You already know you won't be able to use it, do you not?","TWN":"可是，你們應該無法使用這些東西吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 전 원래 내사과 출신이거든요.","JPN":"いいえ。本来私は内偵課出身です。","ENG":"Not yet. But I am originally from the Internal Investigation Department.","TWN":"可以，我出身內務科。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신의 모든 것을 철처하게 심문해드리죠.","JPN":"あなたからすべてをあらいざらい聞きだしてみせます。","ENG":"I'll interrogate you and find out every little detail.","TWN":"我會徹底審出你的一切。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이를테면…… 당신은 벌써 짐작하고 있을 겁니다.","JPN":"たとえば……あなたならもうわかっているでしょう。","ENG":"For instance... You may have already guessed.","TWN":"比如……你應該已經猜到了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신의 존재 자체가 우리 세계를 점점 파멸로 이끈다는 걸.","JPN":"あなたの存在自体がこの世界を破滅に導いていることを。","ENG":"Your existence is what is leading our world into ruin.","TWN":"你的存在本身，就會把我們的世界逐漸引向毀滅。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그건 또 무슨 소리지?","JPN":"それはまた、どういうことだ？","ENG":"What are you talking about?","TWN":"那又是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시치미 떼지 마세요!","JPN":"しらばっくれないでください！","ENG":"Don't play dumb with me!","TWN":"別裝蒜了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크로스로드 작전 때, 저는 다른 세계에 떨어져 엑자일러가 되었던 적이 있습니다.","JPN":"クロスロード作戦のとき、私は他の世界に落ち、エグザイラーになったことがあります。","ENG":"During Operation Crossroads, I was also an Exile in another world.","TWN":"十字路口作戰時，我進入其他世界，成為了流浪者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그때, 만났던 하얀 머리 소녀는 이렇게 말했죠.","JPN":"その際に出会った白い髪の少女はこう言いました。","ENG":"There, I met a white-haired girl, and she told me.","TWN":"我在那裡遇見了一個白髮少女，她對我說過——"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"엑자일러들이 늘어나면, <color=#ffd34c>꽤 귀찮아질 것</color>이라고.","JPN":"エグザイラーが増えると、<color=#ffd34c>かなり厄介だ</color>と。","ENG":"\\"If more Exiles come, it's going to be <color=#ffd34c>quite the bother</color>.\\"","TWN":"如果你這樣的流浪者增加的話，也<color=#ffd34c>蠻麻煩</color>的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그때는 그게 무슨 소리인지 몰랐지만, 당신의 이야기를 듣고 난 뒤에는 알겠더군요.","JPN":"当時はどういう意味か理解できませんでしたが、あなたから話を聞いてわかったんです。","ENG":"I didn't know what she meant back then, but I understood it after hearing your story.","TWN":"那時我還不明白她的意思，但聽了你的故事之後，我就懂了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 분명, 당신의 세계가 수준에 맞지 않는 기술력 때문에 멸망했다고 했어.","JPN":"あなたは確かに、自分の世界が技術水準を超えるテクノロジーによって滅亡したと言っていました。","ENG":"You told me that technology that wasn't meant for your world is what brought destruction to it.","TWN":"你說你自己的世界，是因為使用水準不符的技術才導致滅亡的吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그런 고도로 발달한 기술을 보유한 <color=#ffd34c>엑자일러</color>가 우리 세계에 떨어졌다면……","JPN":"それほど高度に発展したテクノロジーを有する<color=#ffd34c>エグザイラー</color>が私たちの世界に落ちたとしたら……","ENG":"So if an <color=#ffd34c>Exile</color>, who carries all this high technology enters our world...","TWN":"那如果擁有那種高度發展技術的<color=#ffd34c>流浪者</color>落入我們世界的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리 세계의 <color=#ffd34c>침식률</color> 역시 올라가겠지. 그렇지 않습니까?","JPN":"私たちの世界の<color=#ffd34c>侵食率</color>もまた上がる。違いますか？","ENG":"Our <color=#ffd34c>Corruption rate</color> will go up. Isn't that right?","TWN":"我們世界的<color=#ffd34c>侵蝕率</color>也就上升了，不是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇게 생각하면, 아포리아가 나타난 것도 설명할 수 있어.","JPN":"そう考えたら、アポリアの出現も説明がつく。","ENG":"If you think about it like this, it explains the advent of Aporia.","TWN":"這樣一想，阿波利亞的出現也就有跡可循了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"결국, 당신과 당신의 로스트 쉽이 우리 세계에 불시착했기 때문에 우리 세계에 아포리아가 나타난 거야.","JPN":"結局、あなたとあなたのロストシップがこの世界に不時着したから、アポリアが現れたのよ。","ENG":"In the end, it was because of you and your Lost Ship that crashed into our world that Aporia was born.","TWN":"說到底，因為你和你的失落艦船迫降在我們世界，阿波利亞才會出現。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이 말한 대로, 침식률에 의한 인과결정은 멸망한다는 결과에 과정을 끼워 맞출 테니까.","JPN":"侵食率による因果決定においては、滅亡という結果に辻褄を合わせるように過程がつくられていくから。","ENG":"As you said, causality determined by the Corruption rate will force the process to destroy our world regardless of how.","TWN":"這也就是你所說的，是侵蝕率導致的因果所決定的，不管過程如何都會走向滅亡的結果。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신의 혐의를 인정합니까, 안토노프 행정관!","JPN":"自分の嫌疑を認めますか、アントノフ行政官！","ENG":"How do you plead, Officer Antonov?!","TWN":"你承認你的嫌疑嗎，安東諾夫行政官！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 재밌군. 궁지에 몰리니까 꽤나 제법인데.","JPN":"ふふ、面白い。窮地に立たされると、かなりやるもんだな。","ENG":"Ha ha, interesting. I am impressed with how well you are handling this while cornered.","TWN":"呵呵，真有趣。被逼入絕境後，還真是無所不用其極。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐가 그리 우습지?","JPN":"何がそんなにおかしいのですか？","ENG":"What’s so funny?","TWN":"有什麼好笑的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"소령, 나는 자네에 대해서 꽤나 많은 걸 알고 있네.","JPN":"少佐、私は君についてかなり多くのことを知っているんだ。","ENG":"Major, I know quite a lot about you.","TWN":"少校，關於你，我可是知道不少呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네가 필사적으로 이 세계를 지키려는 이유…… 그건 아마도 자네의 상관 때문이겠지.","JPN":"そこまでしてこの世界を必死に守ろうとしているのは……おそらく君の上官のためだろう。","ENG":"The reason you desperately want to save this world... It has something to do with your superior.","TWN":"你拼命守護這個世界的理由……是因為你的長官吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네는 평생, 자네가 존경하는 자의 그림자를 쫓는 운명이니까.","JPN":"君は一生、憧れの存在の影を追いかける運命だからな。","ENG":"Because you are destined to spend your entire life chasing the shadow of the one you admire.","TWN":"因為你註定要一輩子追逐最尊敬之人的影子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고?","JPN":"何ですって？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 그저 존경만으로 그림자를 쫓는 건, 언젠가 벽에 부딪치고 말 거야.","JPN":"しかし憧れだけで影を追いかけるのでは、いずれ壁にぶち当たってしまう。","ENG":"But you're bound to hit a dead end by merely chasing after a shadow with respect.","TWN":"但光靠著滿腔敬意去追逐那道影子，總有一天是會碰壁的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그건 누구보다 내가 가장 잘 알고 있네.","JPN":"私が誰よりもそれを良く知っている。","ENG":"I know that better than anyone.","TWN":"這我比任何人都清楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무슨 헛소리를 하는 거야, 지금!!","JPN":"何を訳のわからないことを！！","ENG":"What are you talking about right now?!","TWN":"你在胡說些什麼呢！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 포위됐어! 얌전히 체포되라고!","JPN":"あなたはすでに包囲されているわ！　おとなしく逮捕されなさい！","ENG":"You're surrounded! Do not resist your arrest!","TWN":"你已經被包圍了！乖乖束手就擒吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"포위? 이 세계에서는 그런 걸 포위라고 하나?","JPN":"包囲？　この世界での包囲はこんなものか？","ENG":"Surrounded? Is this what it means to be \\"surrounded\\" in this world?","TWN":"包圍？在你的世界裡，包圍這個詞是這麼用的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"레베카!!","JPN":"レベッカ！！","ENG":"Rebecca!","TWN":"蕾貝卡！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"언제 불러주나 기다리고 있었다고, 마스터!","JPN":"呼んでくれるのを待っていたぜ、マスター！","ENG":"I've been waiting for your orders, Master!","TWN":"就等你叫我呢，大姊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"전 대원! 이 방위선에서 확보한 물자를 함선에 싣고, 다음 방위선으로 이동한다!","JPN":"全隊員！　この防衛線で確保した物資を艦船に載せ、次の防衛線に移動する！","ENG":"All units! Load all the supplies we secured from this Defense Line! We move on to the next!","TWN":"全體隊員！將這個防線的儲備物資裝載到艦船後，移動至下個防線！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어차피 마지막에 마지막까지 몰리면 방위군도 내 이주 플랜에 동의할 수밖에 없어!","JPN":"どうせ最後の最後まで追い詰められたら、防衛軍もこの移住計画に賛同するしかなくなる！","ENG":"The Defense Force will have no choice but to agree to my plan if they are pushed to the edge!","TWN":"被逼入絕境的保衛軍沒有選擇，只能同意我的移居計畫！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그럼 이런 불필요한 싸움 없이, 항해에 필요한 자원도 쉽게 얻을 수 있겠지.","JPN":"そうなれば無意味な戦いを避けられ、航海に必要な資源も簡単に手に入るだろう。","ENG":"Then there will be no need for tedious quarrels, and we will easily be able to acquire all of the resources required for our voyage.","TWN":"如此我們將避免不必要的戰鬥，輕鬆獲得航行所需的資源。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양! 안토노프가 도주하고 있어요!","JPN":"カリンさん！　アントノフが逃走します！","ENG":"Karin! Antonov is running away!","TWN":"卡琳！安東諾夫要逃了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"막아야 합니다! 여기서 반드시 안토노프 행정관을 체포해서 로스트 쉽을 압류해야 해요!","JPN":"止めなければなりません！　必ずここでアントノフ行政官逮捕してロストシップを押収するんです！","ENG":"Stop her! We must arrest Officer Antonov and seize her Lost Ship!","TWN":"攔住她！一定要在這裡逮捕安東諾夫行政官，並且扣押收繳失落艦船！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};